import{c as a,Q as s,j as n,m as t}from"./chunks/framework.BBA2dIOt.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":1782140424000}'),i={name:"architecture.md"};function o(r,e,l,d,c,p){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>A reference for contributors. Covers process layout, request lifecycle, and how the major subsystems hand data off.</p><h2 id="process-layout" tabindex="-1">Process layout <a class="header-anchor" href="#process-layout" aria-label="Permalink to &quot;Process layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>caddy ─┬─&gt; ember (Go binary)</span></span>
<span class="line"><span>       │     ├─ HTTP API + Fever shim + SPA serve</span></span>
<span class="line"><span>       │     ├─ Background poller (per-feed adaptive ticker)</span></span>
<span class="line"><span>       │     ├─ Summary worker pool (Ollama HTTP client)</span></span>
<span class="line"><span>       │     ├─ DB maintenance goroutine (retention prune / backup / cleanup / OPML / hourly)</span></span>
<span class="line"><span>       │     └─ Cluster backfill goroutine (one-time at startup; idempotent)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       └─&gt; SPA (embedded static files served by ember)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ollama  (sidecar) — model storage + inference</span></span></code></pre></div><p>The single <code>ember</code> binary embeds the Svelte SPA via <code>embed.FS</code> and serves it under <code>/</code>. The API is <code>/api/*</code>; mobile clients use <code>/fever</code>. The poller, summary worker, and maintenance goroutine all share the database via <code>internal/store</code>.</p><h2 id="package-map" tabindex="-1">Package map <a class="header-anchor" href="#package-map" aria-label="Permalink to &quot;Package map&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmd/ember/                    main + probe subcommand + DB maintenance + digest sender</span></span>
<span class="line"><span>internal/api/                 chi router, handlers, middleware (CSRF, rate limit, auth context)</span></span>
<span class="line"><span>internal/auth/                argon2id passwords, securecookie sessions, WebAuthn (passkeys), RequireAuth/Admin middleware</span></span>
<span class="line"><span>internal/config/              env-var loading (typed Config)</span></span>
<span class="line"><span>internal/db/                  SQLite open, pragmas, embedded migrations (goose)</span></span>
<span class="line"><span>internal/digest/              SMTP daily-digest builder + sender (multipart/alt + STARTTLS)</span></span>
<span class="line"><span>internal/feed/                gofeed wrapper + readability fallback fetcher + Discover / DiscoverAll (homepage → one or many feed URLs) + URL normalize (schemeless → https) + CanonicalURL / ClusterID / TitleFingerprint (cross-feed dedup keys)</span></span>
<span class="line"><span>internal/filters/             matcher (field/op/value), apply outcome combiner</span></span>
<span class="line"><span>internal/models/              data types shared across packages</span></span>
<span class="line"><span>internal/opml/                OPML import + export + discovery → subscribe</span></span>
<span class="line"><span>internal/ttrss/               Tiny Tiny RSS migration — XML export parser (articles → one non-polling &quot;Imported&quot; feed) + live JSON API client (subscriptions + categories→folders, plus starred/archived articles)</span></span>
<span class="line"><span>internal/poller/              adaptive scheduler, fetch dispatch, summary queue</span></span>
<span class="line"><span>internal/store/               SQLite CRUD, FTS5 search, app_settings KV, dbops, passkeys, digests, cluster backfill + sibling lookup</span></span>
<span class="line"><span>internal/summarize/           Summarizer interface + Ollama implementation + noop for tests</span></span>
<span class="line"><span>internal/sysinfo/             host-detection (RAM/CPU/GPU) + model recommendation</span></span>
<span class="line"><span>internal/urlcheck/            SSRF block (scheme allowlist + private-IP + service-port refusal)</span></span>
<span class="line"><span>internal/web/                 embed.FS handler for the SPA</span></span>
<span class="line"><span>web/                          Svelte 5 (runes) source; built via Vite, copied to internal/web/dist</span></span></code></pre></div><h2 id="database-schema" tabindex="-1">Database schema <a class="header-anchor" href="#database-schema" aria-label="Permalink to &quot;Database schema&quot;">​</a></h2><p>SQLite. Migrations in <code>internal/db/migrations/*.sql</code>, applied at startup. Key tables:</p><ul><li><code>users</code> — argon2id-hashed passwords; admin flag. <code>last_login_at</code> / <code>prev_login_at</code> track logins so the All-Unread window can extend back to the previous visit.</li><li><code>sessions</code> — server-side rows backing cookies; pruned periodically.</li><li><code>feeds</code> — shared across users; URL-unique. Tracks etag/last-modified/error counters.</li><li><code>subscriptions</code> — <code>(user_id, feed_id)</code> with category, title override, muted flag, and <code>position</code> for drag-reorder.</li><li><code>categories</code> — user-scoped folders with color + position.</li><li><code>articles</code> — shared across users; per-feed dedup by <code>guid</code> and <code>content_hash</code>. Carries <code>cleaned_html</code> (AI ad-stripped). Also stores <code>canonical_url</code>, <code>cluster_id</code>, and <code>title_fingerprint</code> for cross-feed dedup (see <a href="#cross-feed-dedup">Cross-feed dedup</a>); partial indexes <code>idx_articles_cluster</code> and <code>idx_articles_fp_pub</code> skip empty values so unfilled rows never falsely match.</li><li><code>article_state</code> — per-user read/star/later flags.</li><li><code>articles_fts</code> — FTS5 virtual table on title/text/author; kept in sync via triggers. Search is bounded by the admin <strong>search window</strong> (default 48h, capped at the 1-week retention window).</li><li><code>boards</code> + <code>board_articles</code> — user-curated collections.</li><li><code>filters</code> — rule store; engine in <code>internal/filters</code>.</li><li><code>shares</code> — user-to-user article shares.</li><li><code>app_settings</code> — global KV (active model, schedules, branding, tuning).</li><li><code>saved_searches</code> — persisted FTS queries.</li><li><code>article_tags</code> — per-user tags on individual articles.</li><li><code>user_digests</code> — per-user opt-in daily-digest config (view, hour/minute UTC, last-sent timestamp).</li><li><code>passkeys</code> — WebAuthn credentials (credential_id, public_key, sign_count, name, timestamps).</li><li><code>webauthn_sessions</code> — short-lived ceremony state for in-flight register/login flows; reaped after 5 min.</li></ul><p>WAL mode, 64 MiB page cache, 256 MiB mmap, busy_timeout=5s. Single Go connection — writes are serialized (SQLite single-writer); reads are fast enough that the connection pool isn&#39;t the bottleneck at this scale.</p><h2 id="request-lifecycle" tabindex="-1">Request lifecycle <a class="header-anchor" href="#request-lifecycle" aria-label="Permalink to &quot;Request lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTPS                Caddy</span></span>
<span class="line"><span>  └─&gt; :443  ──tls──&gt; ember:8080</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                  chi.Router</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>        ┌──────────────┼──────────────┐</span></span>
<span class="line"><span>        ▼              ▼              ▼</span></span>
<span class="line"><span>   /api/auth/*    /api/*         /fever  (Fever shim)</span></span>
<span class="line"><span>                       │              │</span></span>
<span class="line"><span>                  CSRFVerify          │</span></span>
<span class="line"><span>                  RequireAuth         │</span></span>
<span class="line"><span>                  (RequireAdmin)      │</span></span>
<span class="line"><span>                       │              │</span></span>
<span class="line"><span>                       ▼              ▼</span></span>
<span class="line"><span>                   handlers       fever_handlers</span></span>
<span class="line"><span>                       │              │</span></span>
<span class="line"><span>                       └─&gt; store ─────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>                          SQLite (WAL)</span></span></code></pre></div><p>Browsers store a server-side session cookie + a CSRF cookie. State-changing routes (<code>POST/PATCH/DELETE</code>) must echo the CSRF cookie in <code>X-Ember-CSRF</code>.</p><h2 id="poller-state-machine" tabindex="-1">Poller state machine <a class="header-anchor" href="#poller-state-machine" aria-label="Permalink to &quot;Poller state machine&quot;">​</a></h2><p>Each feed has <code>next_fetch</code> (unix seconds) and an <code>error_count</code>. The poller:</p><ol><li>Every <code>EMBER_POLL_TICK</code> (default 60s): <code>Tick(ctx)</code> queries <code>FeedsDue</code> (next_fetch ≤ now).</li><li>Due feeds fan out across <code>EMBER_POLL_CONCURRENCY</code> worker goroutines.</li><li>Each worker calls <code>Fetcher.Fetch(url, etag, last_modified)</code>: <ul><li>304 → bookkeep last_fetched/next_fetch, error_count = 0.</li><li>2xx → parse with gofeed, optionally enrich short bodies via go-readability, upsert articles (the upsert stamps <code>canonical_url</code>, <code>cluster_id</code>, and <code>title_fingerprint</code> so cross-feed dedup keys are populated at ingest, not only by backfill). The lead image is taken from itunes/RSS <code>&lt;image&gt;</code>, then an image <code>&lt;enclosure&gt;</code>, then <strong>Media RSS</strong> (<code>&lt;media:content&gt;</code> / <code>&lt;media:thumbnail&gt;</code> — how most news feeds, e.g. Fox, ship the article image), then the first inline <code>&lt;img&gt;</code>. At serve time the API rewrites the stored lead-image URL to a signed same-origin <code>/api/img</code> path (see the image proxy under the API surface, and Security › Image proxy) so client-side content/tracker blockers — which match on publisher CDN domains — don&#39;t strip it. Body HTML is then de-cluttered: <code>stripCommentsResidue</code> removes aggregator &quot;Comments&quot;/&quot;Read more&quot; residue, and <code>feed.StripPublisherAds</code> removes curated per-publisher in-body sponsored blocks (matched by ad asset/CTA URL since CSS classes are gone after sanitization; a no-op for hosts we haven&#39;t vetted). The same cleaning runs in the <code>/extract</code> re-extract path, so existing articles can be re-cleaned on demand.</li><li>Error → increment error_count, schedule next try with exponential backoff (capped at <code>MaxInterval</code>).</li></ul></li><li><code>next_fetch</code> is set by <code>AdaptiveInterval</code>, clamped to <code>[floor, MaxInterval]</code>. The <strong>floor</strong> is runtime-configurable — <code>EMBER_POLL_MIN_INTERVAL</code> (default 30m) overlaid by the <code>poll_min_interval_seconds</code> <code>app_settings</code> row (admin UI), resolved live per fetch and clamped to the hard bounds <code>store.PollMinInterval{Floor,Ceil}</code> (5m–24h).</li><li>Newly-inserted articles enqueue on <code>summaryCh</code> (best-effort, drops on full).</li><li>Filters apply per-subscriber as articles land.</li></ol><p>The summary worker is a separate goroutine that drains <code>summaryCh</code>, calls Ollama, writes <code>summary</code> + <code>summary_model</code> + <code>cleaned_html</code>. Failures stamp <code>summary_model = &#39;skipped&#39;</code> so the article still surfaces in the UI.</p><p>Restart safety: <code>enqueuePendingSummaries</code> runs at startup and seeds the channel from any articles with empty <code>summary_model</code>.</p><h2 id="summarizer-pipeline" tabindex="-1">Summarizer pipeline <a class="header-anchor" href="#summarizer-pipeline" aria-label="Permalink to &quot;Summarizer pipeline&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>poller.summarize ─&gt; Summarizer.Summarize(title, text)</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ├─ Ollama: POST /api/generate</span></span>
<span class="line"><span>                       │   prompt = labeled &quot;SUMMARY: / POINTS: / CLEANED:&quot;</span></span>
<span class="line"><span>                       │   options = {temperature, top_p, num_ctx} from app_settings</span></span>
<span class="line"><span>                       │   timeout = 90s, one retry on transient error</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       └─&gt; parseResult(s):</span></span>
<span class="line"><span>                              parseLabeled → parseJSONObject → parseJSONArray</span></span>
<span class="line"><span>                              → line-based fallback</span></span>
<span class="line"><span>                              + cleanBullets (strip markers / inline markdown /</span></span>
<span class="line"><span>                                              prompt-echo / label prefixes)</span></span>
<span class="line"><span>                              + stripEmphasis (** __ * \` &quot; &#39;)</span></span>
<span class="line"><span>                              + cleanParagraph</span></span></code></pre></div><p>Active model + tunables held in <code>atomic.Value</code>/<code>atomic.Pointer</code> on the <code>Ollama</code> struct so the admin API can swap them without restarting.</p><h2 id="cross-feed-dedup" tabindex="-1">Cross-feed dedup <a class="header-anchor" href="#cross-feed-dedup" aria-label="Permalink to &quot;Cross-feed dedup&quot;">​</a></h2><p>When a wire story appears in multiple feeds a user subscribes to (Reuters and The Verge both run the same headline; a Smashing Magazine post is linked from Hacker News with a different referrer), the article list collapses peers to a single row and offers a click-through to siblings.</p><p><strong>Keys.</strong> Three columns on <code>articles</code> are populated at ingest and at backfill (<code>internal/feed/canonical.go</code>, <code>internal/feed/fingerprint.go</code>):</p><ul><li><code>canonical_url</code> — input URL with tracking query params stripped (<code>utm_*</code>, <code>_hs*</code>, <code>mc_*</code>, <code>fbclid</code>, <code>gclid</code>, <code>ref</code>, …), host lowercased, fragment dropped, trailing slash trimmed.</li><li><code>cluster_id</code> — short hex (8 bytes of SHA-1) over the canonical URL. Used as the equality key; the SHA is non-cryptographic, just a content-addressable hash.</li><li><code>title_fingerprint</code> — lowercased title with non-alphanumeric runs collapsed to spaces and a ~25-word stopword list dropped. Rejected (empty) below an 8-rune floor so generic titles (&quot;News&quot;, &quot;Re:&quot;) don&#39;t over-collapse.</li></ul><p><strong>Predicate.</strong> The list query in <code>internal/store/articles.go</code> keeps the lowest-id row in each cluster and filters peers via <code>NOT EXISTS</code> over an OR&#39;d match:</p><ol><li><strong>Same <code>cluster_id</code></strong> — exact canonical-URL match. Always clusters.</li><li><strong>Same <code>title_fingerprint</code> within 48h</strong> of the candidate&#39;s <code>published_at</code> — catches wire stories under different URLs. The window keeps a recurring headline (&quot;Apple Q3 earnings&quot;) from collapsing across years.</li></ol><p>The suppressor sibling must satisfy the <strong>same</strong> window, summary gate, muted, and read/star/later predicate as the rows being listed. Otherwise a lower-id copy the user can&#39;t see (already read, out of window, unsummarized) would silently suppress its visible copies and collapse a badge to 0 — so a row is only deduped against a peer actually present in the same view.</p><p>Only the <code>shared</code> view (explicit one-off share) and board views (explicit curation) skip the predicate. Per-feed and per-category views dedup too: a duplicated story is owned by its lowest-id (first-ingested) feed and counted/shown once. Their sidebar badges go through <code>CountUnreadByFeed</code> / <code>CountUnreadByCategory</code>, which reuse <code>buildArticleFilter</code>, so per-feed badges sum to All Unread and never exceed their column. Rows with both <code>cluster_id</code> and <code>title_fingerprint</code> empty pass unconditionally (no signal in either dimension). <strong>Star/later/tag state is per-row</strong> and not propagated across siblings (you can save or tag one specific copy). <strong>Read state, however, propagates across the cluster</strong>: because the suppressor only hides <em>unread</em> copies, marking just the visible winner read would let its hidden sibling resurface as unread on the next poll — a phantom duplicate. So every mark-read path (opening an article, the keyboard read toggle, and bulk &quot;mark all read&quot;) routes through <code>MarkReadWithSiblings</code> (the <code>include_siblings</code> flag on <code>POST /api/articles/read</code>), which also marks the cluster&#39;s still-unread siblings read. Reading one copy of a syndicated story means you&#39;ve read the story.</p><p><strong><code>dup_count</code> + sibling expansion.</strong> The list query also returns a <code>dup_count</code> per row: the number of other articles in the user&#39;s subscription set that share either match. The SPA renders this as the &quot;Also in N feeds&quot; pill. Clicking the pill calls <code>GET /api/articles/{id}/cluster</code>, which returns the sibling rows (article id, feed id + title, raw URL, per-user read/starred) so the popover can show them.</p><p><strong>Backfill.</strong> Historical rows inserted before migrations <code>0013_dedup_canonical.sql</code> / <code>0014_title_fingerprint.sql</code> start with empty keys. <code>Store.BackfillClustersAsync</code> (kicked off in <code>cmd/ember/main.go</code>) walks them in 500-row batches in a goroutine so it doesn&#39;t block startup. The partial indexes (<code>idx_articles_cluster</code>, <code>idx_articles_fp_pub</code>) exclude empty values, so unfilled rows never falsely cluster with each other while the backfill is in flight. Idempotent — after the corpus is full, every restart is a single SELECT that returns zero rows.</p><h2 id="spa" tabindex="-1">SPA <a class="header-anchor" href="#spa" aria-label="Permalink to &quot;SPA&quot;">​</a></h2><ul><li>Svelte 5 with runes (<code>$state</code>, <code>$derived</code>, <code>$effect</code>, <code>$props</code>).</li><li>Vite 5 build, output copied to <code>internal/web/dist</code>, served via <code>embed.FS</code>.</li><li>Typed fetch client in <code>web/src/lib/api.ts</code> (throws <code>ApiError</code>).</li><li>Stores in <code>web/src/lib/stores.ts</code> for user, feeds, categories, boards, articles, themes, branding, new-article counter, etc.</li><li>15s auto-refresh poll while the tab is visible; SSE not used — REST polling is simpler and fits the cadence. In the <strong>Fresh</strong> and <strong>All Unread</strong> views the auto-poll is <em>non-disruptive</em>: newly-arrived articles are held in a backlog (<code>pendingNewIds</code> in <code>stores.ts</code>) and counted once rather than injected into the list under a scrolling reader. They page in on the next full load — <code>loadArticles</code> (which <code>clearNewArticleBacklog</code> resets) — e.g. the refill after &quot;Mark all read&quot;. The explicit &quot;Refresh feeds now&quot; control calls <code>pollForNewArticles({ immediate: true })</code> to bypass the backlog; all other views merge new articles immediately.</li><li><strong>Mark all read</strong> in Fresh / All Unread drops the read cards and pages in the next unread batch, with a one-shot <strong>grace</strong> for the article currently open: that card is kept (greyed via <code>.story.read</code>, still in <code>articles.items</code> so the reader pane keeps it) so you can finish reading; the next &quot;Mark all read&quot; hides it. Tracked by a <code>graceUsedId</code> ledger because opening an article auto-marks it read, so <code>is_read</code> can&#39;t distinguish the first click. Article-body links are rewritten to <code>target=&quot;_blank&quot; rel=&quot;noopener noreferrer&quot;</code> after render (<code>lib/links.forceNewTabLinks</code>) so they open in a new tab.</li><li>Service worker (<code>web/public/sw.js</code>) caches assets immutably and falls back to cached shell when offline.</li></ul><h2 id="admin-endpoints-admin-only" tabindex="-1">Admin endpoints (admin-only) <a class="header-anchor" href="#admin-endpoints-admin-only" aria-label="Permalink to &quot;Admin endpoints (admin-only)&quot;">​</a></h2><ul><li><code>GET /api/admin/llm</code> — detected hardware, recommendation, installed models, current model + options.</li><li><code>POST /api/admin/llm/model</code> / <code>…/pull</code> / <code>…/delete</code> / <code>…/options</code> — switch / pull / delete / tune.</li><li><code>GET /api/branding</code> (public) / <code>POST /api/admin/branding</code> (admin).</li><li><code>GET /api/admin/db</code> — size, page count, recent backups, schedules.</li><li><code>POST /api/admin/db/backup</code> / <code>…/cleanup</code> / <code>…/schedule</code> — manual + scheduled maintenance.</li><li><code>POST /api/feeds/resummarize-all</code> — re-process every article after a prompt change.</li><li><code>GET /api/admin/session</code> / <code>POST /api/admin/session/ttl</code> — server-wide session cookie lifetime.</li><li><code>GET /api/admin/settings</code> / <code>PATCH /api/admin/settings</code> — SMTP relay config + initial-backlog window. Overlays env-derived defaults at runtime; digest sender re-resolves every tick.</li><li><code>POST /api/admin/settings/email-test</code> — send a one-off diagnostic message through the live SMTP config.</li></ul><p>Auth-required (not admin-only):</p><ul><li><code>POST /api/articles/{id}/extract</code> — on-demand readability re-run for the reader pane&#39;s &quot;Re-extract&quot; button. Subject to the same SSRF check as the poller&#39;s automatic enrichment.</li><li><code>GET /api/img?u=…&amp;s=…</code> — same-origin image proxy for article lead images. The API signs the source URL (HMAC keyed off <code>EMBER_SESSION_KEY</code>, domain-separated) when it rewrites <code>image_url</code> in list/detail/search responses, so the endpoint is a capability — it only fetches images Ember itself selected, never arbitrary client input. The outbound fetch runs through <code>urlcheck.Check</code>, accepts only <code>image/*</code>, and is size- (10 MiB) and time- (15 s) bounded. Streams through with a 1-day <code>Cache-Control</code>; no server-side cache.</li></ul><h2 id="e2e" tabindex="-1">E2E <a class="header-anchor" href="#e2e" aria-label="Permalink to &quot;E2E&quot;">​</a></h2><p><code>web/e2e/*.spec.ts</code> (Playwright). The binary in <code>EMBER_TEST_MODE=1</code> seeds a deterministic admin + 1 feed + 12 articles with known content, so specs can assert on titles/excerpts directly. Axe-core runs against the major screens for WCAG 2.1 AA.</p>`,40)])])}const m=a(i,[["render",o]]);export{h as __pageData,m as default};
